#include <stdio.h>
#include <stdlib.h>
#include <string.h>

void backtrack(char *s, int start, int **result, int *returnSize, char ***resultTemp, int *returnSizeTemp) {
    if (start == strlen(s)) {
        *returnSize += 1;
        *result = realloc(*result, sizeof(int *) * *returnSize);
        (*result)[*returnSize - 1] = malloc(sizeof(int) * *returnSizeTemp);
        for (int i = 0; i < *returnSizeTemp; i++) {
            (*result)[*returnSize - 1][i] = strlen((*resultTemp)[i]);
        }
        return;
    }
    for (int i = start; i < strlen(s); i++) {
        char *temp = malloc(sizeof(char) * (i - start + 2));
        strncpy(temp, s + start, i - start + 1);
        temp[i - start + 1] = '\0';
        if (isPalindrome(temp)) {
            *returnSizeTemp += 1;
            *resultTemp = realloc(*resultTemp, sizeof(char *) * *returnSizeTemp);
            (*resultTemp)[*returnSizeTemp - 1] = temp;
            backtrack(s, i + 1, result, returnSize, resultTemp, returnSizeTemp);
            *returnSizeTemp -= 1;
            free((*resultTemp)[*returnSizeTemp]);
            *resultTemp = realloc(*resultTemp, sizeof(char *) * *returnSizeTemp);
        } else {
            free(temp);
        }
    }
}

int **partition(char *s, int *returnSize) {
    *returnSize = 0;
    int returnSizeTemp = 0;
    int **result = NULL;
    char ***resultTemp = malloc(sizeof(char **));
    *resultTemp = NULL;
    backtrack(s, 0, &result, returnSize, resultTemp, &returnSizeTemp);
    free(*resultTemp);
    free(resultTemp);
    return result;
}

int isPalindrome(char *s) {
    int start = 0;
    int end = strlen(s) - 1;
    while (start < end) {
        if (s[start] != s[end]) {
            return 0;
        }
        start++;
        end--;
    }
    return 1;
}

